		assertThat(nullPathResponse.getRedirectedUrl()).isEqualTo("/proxy/summary");

		MockHttpServletRequest slashRequest = new MockHttpServletRequest("GET", "/proxy/");
		slashRequest.setRequestURI("/proxy/");
		configureUrl(slashRequest);
		slashRequest.setPathInfo("/");
		MockHttpServletResponse slashResponse = new MockHttpServletResponse();
		servlet.service(slashRequest, slashResponse);
		assertThat(slashResponse.getRedirectedUrl()).isEqualTo("/proxy/summary");

		MockHttpServletRequest nestedRequest = new MockHttpServletRequest("GET", "/proxy/summary");
		nestedRequest.setRequestURI("/proxy/summary");
		configureUrl(nestedRequest);
		nestedRequest.setServletPath("/proxy");
		nestedRequest.setPathInfo("/summary");
