	@Test
	void serviceHandlesCachingResetAndUnconfiguredPaths() throws Exception {
		ProxyRepositoryServlet servlet = initServlet();

		MockHttpServletRequest firstRequest = new MockHttpServletRequest("GET", "/proxy/summary");
		firstRequest.setRequestURI("/proxy/summary");
		configureUrl(firstRequest);
		firstRequest.setServletPath("/proxy");
		firstRequest.setPathInfo("/summary");
		MockHttpServletResponse firstResponse = new MockHttpServletResponse();
		servlet.service(firstRequest, firstResponse);
		long lastModified = firstResponse.getDateHeader("Last-Modified");
		assertThat(lastModified).isPositive();

		RecordingRepositoryServlet.resetInvocation();
		MockHttpServletRequest cachedRequest = new MockHttpServletRequest("GET", "/proxy/summary");
		cachedRequest.setRequestURI("/proxy/summary");
		configureUrl(cachedRequest);
		cachedRequest.setServletPath("/proxy");
		cachedRequest.setPathInfo("/summary");
		cachedRequest.addHeader("If-Modified-Since", Long.MAX_VALUE);
		MockHttpServletResponse cachedResponse = new MockHttpServletResponse();
		servlet.service(cachedRequest, cachedResponse);
		assertThat(cachedResponse.getStatus()).isEqualTo(HttpServletResponse.SC_NOT_MODIFIED);
		assertThat(RecordingRepositoryServlet.lastServletPath).isNull();

		servlet.resetCache();
		MockHttpServletRequest uncachedRequest = new MockHttpServletRequest("GET", "/proxy/summary;view=1");
		uncachedRequest.setRequestURI("/proxy/summary;view=1");
		configureUrl(uncachedRequest);
		uncachedRequest.setServletPath("/proxy");
		uncachedRequest.setPathInfo("/summary");
		uncachedRequest.addHeader("If-Modified-Since", Long.MAX_VALUE);
		MockHttpServletResponse uncachedResponse = new MockHttpServletResponse();
		servlet.service(uncachedRequest, uncachedResponse);
		assertThat(RecordingRepositoryServlet.lastServletPath).isEqualTo("/proxy/summary");

		MockHttpServletRequest postRequest = new MockHttpServletRequest("POST", "/proxy/summary");
		postRequest.setRequestURI("/proxy/summary");
		configureUrl(postRequest);
		postRequest.setServletPath("/proxy");
		postRequest.setPathInfo("/summary");
		servlet.service(postRequest, new MockHttpServletResponse());

		MockHttpServletRequest missingRequest = new MockHttpServletRequest("GET", "/proxy/missing");
		missingRequest.setRequestURI("/proxy/missing");
		configureUrl(missingRequest);
		missingRequest.setPathInfo("/missing");
		assertThatThrownBy(() -> servlet.service(missingRequest, new MockHttpServletResponse()))
				.isInstanceOf(BadRequestException.class)
				.hasMessageContaining("Unconfigured path: /missing");
	}

	@Test
	void serviceRoundsStaleLastModifiedTimestampsUpToWholeSeconds() throws Exception {
		ProxyRepositoryServlet servlet = initServlet();
		setLastModified(servlet, 1L);

		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/proxy/summary");
		request.setRequestURI("/proxy/summary");
		configureUrl(request);
		request.setServletPath("/proxy");
		request.setPathInfo("/summary");

		servlet.service(request, new MockHttpServletResponse());

		assertThat(getLastModified(servlet)).isGreaterThan(1L);
		assertThat(getLastModified(servlet) % 1000L).isZero();
	}

	@Test
	void serviceLeavesWholeSecondTimestampsUntouched() throws Exception {
		ProxyRepositoryServlet servlet = initServlet();
		setLastModified(servlet, 2000L);

		MockHttpServletRequest request = new MockHttpServletRequest("GET", "/proxy/summary");
		request.setRequestURI("/proxy/summary");
		configureUrl(request);
		request.setServletPath("/proxy");
		request.setPathInfo("/summary");

		servlet.service(request, new MockHttpServletResponse());

		assertThat(getLastModified(servlet)).isEqualTo(2000L);
	}

